#include <bits/stdc++.h>
using namespace std;
const int mod=9999973;
long long n,m,ans,dp[105][105][105];
int main()
{
    cin>>n>>m;
    dp[0][0][0]=1;
    for(long long i=1;i<=n;i++)
    {
        for(long long j=0;j<=m;j++)
        {
            for(long long k=0;k+j<=m;k++)
            {
                dp[i][j][k]=dp[i-1][j][k];
                if(j>=1)
                {
                    dp[i][j][k]+=dp[i-1][j-1][k]*(m-j-k+1);
                    dp[i][j][k]%=mod;
                    if(j-1>=1) dp[i][j][k]+=dp[i-1][j-2][k]*(m-j-k+2)*(m-j-k+1)/2;
                    dp[i][j][k]%=mod;
                }
                if(k>=1)
                {
                    dp[i][j][k]+=((dp[i-1][j+1][k-1]*(j+1))%mod+(dp[i-1][j][k-1]*j*(m-j-k+1))%mod)%mod;
                    if(k-1>=1) dp[i][j][k]+=(dp[i-1][j+2][k-2]*(j+2)*(j+1)/2);
                    dp[i][j][k]%=mod;
                }
            }
        }
    }
    for(int i=0;i<=m;i++)
    {
        for(int j=0;j<=m;j++)
        {
            ans=(ans+dp[n][i][j])%mod;
        }
    }
    cout<<ans%mod;
    return 0;
}
